class Graph:
    def __init__(self, data=None):
        self.nodes, self.edges, self.attrs = [], [], {}
        if data is None: return
        if not isinstance(data, list): raise TypeError("Graph data malformed")
        for item in data:
            if len(item) < 2: raise TypeError("Graph item incomplete")
            t = item[0]
            if t == ATTR:
                if len(item) != 3: raise ValueError("Attribute is malformed")
                self.attrs[item[1]] = item[2]
            elif t == NODE:
                if len(item) != 3: raise ValueError("Node is malformed")
                self.nodes.append(Node(item[1], item[2]))
            elif t == EDGE:
                if len(item) != 4: raise ValueError("Edge is malformed")
                self.edges.append(Edge(item[1], item[2], item[3]))
            else: raise ValueError("Unknown item")

STATUS_WIN, STATUS_LOSE, STATUS_ONGOING = "win", "lose", "ongoing"
class Hangman:
    def __init__(self, word):
        self.remaining_guesses = 9
        self.status = STATUS_ONGOING
        self.word = word
        self.guessed = set()
    def guess(self, char):
        if self.status != STATUS_ONGOING: raise ValueError("The game has already ended.")
        if char in self.guessed:
            self.remaining_guesses -= 1
        else:
            self.guessed.add(char)
            if char not in self.word:
                self.remaining_guesses -= 1
        if all(c in self.guessed for c in self.word):
            self.status = STATUS_WIN
        elif self.remaining_guesses < 0:
            self.status = STATUS_LOSE
    def get_masked_word(self):
        return "".join(c if c in self.guessed else "_" for c in self.word)
    def get_status(self):
        return self.status

