from copy import deepcopy
class Tree:
    def __init__(self, label, children=None):
        self.label = label
        self.children = list(children) if children else []
    def to_dict(self): return {self.label: [c.to_dict() for c in sorted(self.children)]}
    def __str__(self, indent=None): return dumps(self.to_dict(), indent=indent)
    def __lt__(self, other): return self.label < other.label
    def __eq__(self, other): return self.to_dict() == other.to_dict()
    def from_pov(self, from_node):
        path = self._find_path(from_node)
        if not path: raise ValueError("Tree could not be reoriented")
        for i in range(len(path) - 1):
            ancestor, descendant = path[i], path[i+1]
            ancestor.children = [c for c in ancestor.children if c.label != descendant.label]
            descendant.children = list(descendant.children) + [ancestor]
        return path[-1]
    def path_to(self, from_node, to_node):
        tree_copy = deepcopy(self)
        try:
            new_root = tree_copy.from_pov(from_node)
        except ValueError:
            raise ValueError("Tree could not be reoriented")
        path = new_root._find_path(to_node)
        if not path: raise ValueError("No path found")
        return [node.label for node in path]
    def _find_path(self, target):
        if self.label == target: return [self]
        for c in self.children:
            p = c._find_path(target)
            if p: return [self] + p
        return None

class BowlingGame:
    def __init__(self): self.rolls = []
    def roll(self, pins):
        if pins < 0: raise ValueError("Negative roll is invalid")
        if pins > 10: raise ValueError("Pin count exceeds pins on the lane")
        if self._game_complete(): raise ValueError("Cannot roll after game is over")
        self.rolls.append(pins)
        if not self._valid(): self.rolls.pop(); raise ValueError("Pin count exceeds pins on the lane")
    def score(self):
        if not self._game_complete(): raise ValueError("Score cannot be taken until the end of the game")
        total, i = 0, 0
        for _ in range(10):
            if self.rolls[i] == 10: total += 10 + self.rolls[i+1] + self.rolls[i+2]; i += 1
            elif self.rolls[i] + self.rolls[i+1] == 10: total += 10 + self.rolls[i+2]; i += 2
            else: total += self.rolls[i] + self.rolls[i+1]; i += 2
        return total
    def _frame_start(self):
        i = 0
        for f in range(9):
            if i >= len(self.rolls): return i, f
            i += 1 if self.rolls[i] == 10 else 2
        return i, 9
    def _game_complete(self):
        i, f = self._frame_start()
        if f < 9: return False
        t = self.rolls[i:]
        if len(t) < 2: return False
        if t[0] == 10: return len(t) >= 3
        if t[0] + t[1] == 10: return len(t) >= 3
        return len(t) >= 2
    def _valid(self):
        i, f = self._frame_start()
        if f < 9:
            if i < len(self.rolls) and self.rolls[i] != 10 and i+1 < len(self.rolls):
                if self.rolls[i] + self.rolls[i+1] > 10: return False
        else:
            t = self.rolls[i:]
            if len(t) == 2 and t[0] != 10 and t[0] + t[1] > 10: return False
            if len(t) == 3:
                if t[0] == 10:
                    if t[1] != 10 and t[1] + t[2] > 10: return False
                elif t[0] + t[1] == 10: pass
        return True

