class StackUnderflowError(Exception): pass
def evaluate(input_data):
    stack = []
    defines = {}
    for line in input_data:
        tokens = line.lower().split()
        i = 0
        while i < len(tokens):
            token = tokens[i]
            if token == ":":
                i += 1
                if i >= len(tokens): raise ValueError("undefined operation")
                name = tokens[i]
                if name.lstrip('-').isdigit(): raise ValueError("illegal operation")
                definition = []
                i += 1
                while i < len(tokens) and tokens[i] != ";":
                    definition.append(tokens[i])
                    i += 1
                if i == len(tokens): raise ValueError("undefined operation")
                resolved_def = []
                for d in definition:
                    if d in defines: resolved_def.extend(defines[d])
                    else: resolved_def.append(d)
                defines[name] = resolved_def
            elif token in defines:
                tokens[i+1:i+1] = defines[token]
            elif token.lstrip('-').isdigit():
                stack.append(int(token))
            else:
                if token == "+":
                    if len(stack) < 2: raise StackUnderflowError("Insufficient number of items in stack")
                    stack.append(stack.pop() + stack.pop())
                elif token == "-":
                    if len(stack) < 2: raise StackUnderflowError("Insufficient number of items in stack")
                    b, a = stack.pop(), stack.pop(); stack.append(a - b)
                elif token == "*":
                    if len(stack) < 2: raise StackUnderflowError("Insufficient number of items in stack")
                    stack.append(stack.pop() * stack.pop())
                elif token == "/":
                    if len(stack) < 2: raise StackUnderflowError("Insufficient number of items in stack")
                    b, a = stack.pop(), stack.pop()
                    if b == 0: raise ZeroDivisionError("divide by zero")
                    stack.append(int(a / b))
                elif token == "dup":
                    if not stack: raise StackUnderflowError("Insufficient number of items in stack")
                    stack.append(stack[-1])
                elif token == "drop":
                    if not stack: raise StackUnderflowError("Insufficient number of items in stack")
                    stack.pop()
                elif token == "swap":
                    if len(stack) < 2: raise StackUnderflowError("Insufficient number of items in stack")
                    b, a = stack.pop(), stack.pop(); stack.extend([b, a])
                elif token == "over":
                    if len(stack) < 2: raise StackUnderflowError("Insufficient number of items in stack")
                    stack.append(stack[-2])
                else: raise ValueError("undefined operation")
            i += 1
    return stack

