def total(basket):
    if not basket: return 0
    counts = [basket.count(x) for x in set(basket)]
    counts.sort(reverse=True)
    costs = {1: 800, 2: 1520, 3: 2160, 4: 2560, 5: 3000}
    groups = []
    while sum(counts) > 0:
        s = set()
        for i, c in enumerate(counts):
            if c > 0 and i not in s:
                s.add(i)
                counts[i] -= 1
                if len(s) == 5: break
        groups.append(len(s))
    while 5 in groups and 3 in groups:
        groups.remove(5)
        groups.remove(3)
        groups.append(4)
        groups.append(4)
    return sum(costs[g] for g in groups)

