def allmax(iterable, key=None):
    result, maxval = [], None
    key = key or (lambda x: x)
    for item in iterable:
        val = key(item)
        if not result or val > maxval:
            result, maxval = [item], val
        elif val == maxval:
            result.append(item)
    return result
def hand_rank(hand):
    hand = hand.replace('10', 'T').split()
    ranks = ['..23456789TJQKA'.index(r) for r, s in hand]
    ranks.sort(reverse=True)
    is_flush = len(set(s for r, s in hand)) == 1
    is_straight = (max(ranks) - min(ranks) == 4) and (len(set(ranks)) == 5)
    if ranks == [14, 5, 4, 3, 2]:
        ranks = [5, 4, 3, 2, 1]
        is_straight = True
    groups = [(ranks.count(x), x) for x in set(ranks)]
    groups.sort(key=lambda x: (x[0], x[1]), reverse=True)
    counts, score_ranks = zip(*groups)
    if is_straight and is_flush: return (8, ranks)
    if counts == (4, 1): return (7, score_ranks)
    if counts == (3, 2): return (6, score_ranks)
    if is_flush: return (5, ranks)
    if is_straight: return (4, ranks)
    if counts == (3, 1, 1): return (3, score_ranks)
    if counts == (2, 2, 1): return (2, score_ranks)
    if counts == (2, 1, 1, 1): return (1, score_ranks)
    return (0, ranks)

import re
class PhoneNumber:
    def __init__(self, number):
        if any(c.isalpha() for c in number): raise ValueError('letters not permitted')
        if any(c in "@:!" for c in number): raise ValueError('punctuations not permitted')
        d = re.sub(r'\D', '', number)
        if len(d) < 10: raise ValueError('must not be fewer than 10 digits')
        if len(d) > 11: raise ValueError('must not be greater than 11 digits')
        if len(d) == 11:
            if not d.startswith('1'): raise ValueError('11 digits must start with 1')
            d = d[1:]
        if d[0] == '0': raise ValueError('area code cannot start with zero')
        if d[0] == '1': raise ValueError('area code cannot start with one')
        if d[3] == '0': raise ValueError('exchange code cannot start with zero')
        if d[3] == '1': raise ValueError('exchange code cannot start with one')
        self.number = d
        self.area_code = d[:3]
    def pretty(self):
        return f'({self.number[:3]})-{self.number[3:6]}-{self.number[6:]}'

def can_chain(dominoes):
    if not dominoes: return []
    for i in range(len(dominoes)):
        res = solve([dominoes[i]], dominoes[:i]+dominoes[i+1:])
        if res: return res
        if dominoes[i][0] != dominoes[i][1]:
            res = solve([tuple(reversed(dominoes[i]))], dominoes[:i]+dominoes[i+1:])
            if res: return res
    return None
def solve(chain, rest):
    if not rest: return chain if chain[0][0] == chain[-1][1] else None
    tgt = chain[-1][1]
    for i, d in enumerate(rest):
        if d[0] == tgt:
            res = solve(chain + [d], rest[:i]+rest[i+1:])
            if res: return res
        elif d[1] == tgt:
            res = solve(chain + [tuple(reversed(d))], rest[:i]+rest[i+1:])
            if res: return res
    return None

import math
def encode(plain, a, b):
    if math.gcd(a, 26) != 1: raise ValueError('Error')
    res = []
    for c in plain:
        if c.isalnum():
            if c.isdigit(): res.append(c)
            elif c.isalpha():
                res.append(chr(((a * (ord(c.lower())-97) + b) % 26) + 97))
    blk = ''.join(res)
    return ' '.join(blk[i:i+5] for i in range(0, len(blk), 5))
def decode(cipher, a, b):
    if math.gcd(a, 26) != 1: raise ValueError('Error')
    inv = pow(a, -1, 26)
    res = []
    for c in cipher:
        if c.isalnum():
            if c.isdigit(): res.append(c)
            elif c.isalpha():
                res.append(chr(((inv * (ord(c.lower())-97 - b)) % 26) + 97))
    return ''.join(res)

