def grep(pattern, flags, files):
    res = []
    n, l, i_case, v, x = '-n' in flags, '-l' in flags, '-i' in flags, '-v' in flags, '-x' in flags
    for file in files:
        try:
            with open(file) as f: lines = f.readlines()
        except: continue
        for idx, line in enumerate(lines):
            txt = line.rstrip('\n')
            p, t = (pattern.lower(), txt.lower()) if i_case else (pattern, txt)
            match = (p == t) if x else (p in t)
            if v: match = not match
            if match:
                if l:
                    res.append(file + '\n')
                    break
                pre = ''
                if len(files) > 1: pre += f'{file}:'
                if n: pre += f'{idx+1}:'
                res.append(f'{pre}{txt}\n')
    return ''.join(res)

