def answer(question):
    if question == 'What is?': raise ValueError('syntax error')
    if not question.startswith('What is ') or not question.endswith('?'): raise ValueError('unknown operation')
    body = question[8:-1].strip()
    if not body: raise ValueError('syntax error')
    valid_ops = {'plus', 'minus', 'multiplied', 'divided', 'by'}
    words = body.split()
    for w in words:
        if not (w.isdigit() or w.lstrip('-').isdigit()) and w not in valid_ops: raise ValueError('unknown operation')
    expr = body.replace('plus', '+').replace('minus', '-').replace('multiplied by', '*').replace('divided by', '/')
    tokens = expr.split()
    if not tokens or len(tokens) % 2 == 0: raise ValueError('syntax error')
    try:
        res = int(tokens[0])
        i = 1
        while i < len(tokens):
            op = tokens[i]
            num = int(tokens[i+1])
            if op == '+': res += num
            elif op == '-': res -= num
            elif op == '*': res *= num
            elif op == '/': res //= num
            i += 2
        return res
    except: raise ValueError('syntax error')

class ConnectGame:
    def __init__(self, board):
        self.board = [row.replace(" ", "") for row in board.splitlines()]
        self.height = len(self.board)
        self.width = len(self.board[0])

    def get_winner(self):
        if self.check('O', self.width, self.height, False):
            return 'O'
        if self.check('X', self.height, self.width, True):
            return 'X'
        return ""

    def check(self, player, dim1, dim2, transpose):
        start_nodes = []
        for r in range(self.height):
            for c in range(self.width):
                if self.board[r][c] == player:
                    if (transpose and c == 0) or (not transpose and r == 0):
                        start_nodes.append((r, c))
        queue = start_nodes
        seen = set(start_nodes)
        while queue:
            r, c = queue.pop(0)
            if (transpose and c == self.width - 1) or (not transpose and r == self.height - 1):
                return True
            for dr, dc in [(-1, 0), (-1, 1), (0, -1), (0, 1), (1, -1), (1, 0)]:
                nr, nc = r + dr, c + dc
                if 0 <= nr < self.height and 0 <= nc < self.width and self.board[nr][nc] == player and (nr, nc) not in seen:
                    seen.add((nr, nc))
                    queue.append((nr, nc))
        return False

WHITE, BLACK, NONE = 'W', 'B', ''
class Board:
    def __init__(self, board):
        self.board = [list(row) for row in board]
        self.h = len(board)
        self.w = len(board[0])
    def territory(self, x, y):
        if not (0 <= x < self.w and 0 <= y < self.h): raise ValueError("Invalid coordinate")
        if self.board[y][x] != ' ': return NONE, set()
        territory, borders = set(), set()
        queue = [(x, y)]
        visited = {(x, y)}
        while queue:
            cx, cy = queue.pop(0)
            territory.add((cx, cy))
            for dx, dy in [(0, 1), (0, -1), (1, 0), (-1, 0)]:
                nx, ny = cx + dx, cy + dy
                if 0 <= nx < self.w and 0 <= ny < self.h:
                    if self.board[ny][nx] == ' ' and (nx, ny) not in visited:
                        visited.add((nx, ny))
                        queue.append((nx, ny))
                    elif self.board[ny][nx] != ' ':
                        borders.add(self.board[ny][nx])
        owner = borders.pop() if len(borders) == 1 else NONE
        return owner, territory
    def territories(self):
        res = {BLACK: set(), WHITE: set(), NONE: set()}
        processed = set()
        for y in range(self.h):
            for x in range(self.w):
                if self.board[y][x] == ' ' and (x, y) not in processed:
                    owner, terr = self.territory(x, y)
                    res[owner].update(terr)
                    processed.update(terr)
        return res
